codeExercises.solution:
const express = require('express');
const app = express();
const port = 8017;

app.get('/', (req, res) => {
  res.json({ message: "Welcome to the Trello Clone API" });
});

app.listen(port, () => {
  console.log(`Server is running at http://localhost:${port}`);
});
